  1→use std::path::{Path, PathBuf};
  2→
  3→use anyhow::Context;
  4→
  5→/// Environment and configuration for a mementor-enabled project.
  6→#[derive(Clone, Debug)]
  7→pub struct MementorContext {
  8→    /// The resolved primary worktree root (used for DB, settings, etc.).
  9→    project_root: PathBuf,
 10→    /// The actual working directory (may differ from `project_root` in a
 11→    /// linked worktree or subdirectory).
 12→    cwd: PathBuf,
 13→    /// `true` when `cwd` is inside a linked (non-primary) git worktree.
 14→    is_linked_worktree: bool,
 15→    log_dir: Option<PathBuf>,
 16→    /// Directory where embedding model files are stored.
 17→    /// Default: `~/.mementor/models/`, override: `MEMENTOR_MODEL_DIR` env var.
 18→    model_cache_dir: PathBuf,
 19→}
 20→
 21→impl MementorContext {
 22→    /// Resolve the default model cache directory.
 23→    ///
 24→    /// Uses `MEMENTOR_MODEL_DIR` env var if set, otherwise `~/.mementor/models/`.
 25→    fn default_model_cache_dir() -> anyhow::Result<PathBuf> {
 26→        if let Ok(dir) = std::env::var("MEMENTOR_MODEL_DIR") {
 27→            return Ok(PathBuf::from(dir));
 28→        }
 29→        let home = dirs::home_dir().context("Could not determine home directory")?;
 30→        Ok(home.join(".mementor").join("models"))
 31→    }
 32→
 33→    /// Create a new context rooted at the given path (no log directory).
 34→    ///
 35→    /// Sets `cwd` equal to `project_root`. Use [`Self::with_cwd_and_log_dir`]
 36→    /// when the actual working directory differs from the project root.
 37→    pub fn new(project_root: PathBuf) -> anyhow::Result<Self> {
 38→        Ok(Self {
 39→            cwd: project_root.clone(),
 40→            project_root,
 41→            is_linked_worktree: false,
 42→            log_dir: None,
 43→            model_cache_dir: Self::default_model_cache_dir()?,
 44→        })
 45→    }
 46→
 47→    /// Create a new context with an explicit log directory.
 48→    ///
 49→    /// Sets `cwd` equal to `project_root`.
 50→    pub fn with_log_dir(project_root: PathBuf, log_dir: Option<PathBuf>) -> anyhow::Result<Self> {
 51→        Ok(Self {
 52→            cwd: project_root.clone(),
 53→            project_root,
 54→            is_linked_worktree: false,
 55→            log_dir,
 56→            model_cache_dir: Self::default_model_cache_dir()?,
 57→        })
 58→    }
 59→
 60→    /// Create a new context with separate cwd and project root.
 61→    ///
 62→    /// Use this when the actual working directory (e.g., a linked worktree or
 63→    /// subdirectory) differs from the resolved primary worktree root.
 64→    pub fn with_cwd_and_log_dir(
 65→        cwd: PathBuf,
 66→        project_root: PathBuf,
 67→        is_linked_worktree: bool,
 68→        log_dir: Option<PathBuf>,
 69→    ) -> anyhow::Result<Self> {
 70→        Ok(Self {
 71→            project_root,
 72→            cwd,
 73→            is_linked_worktree,
 74→            log_dir,
 75→            model_cache_dir: Self::default_model_cache_dir()?,
 76→        })
 77→    }
 78→
 79→    /// Override the model cache directory.
 80→    #[must_use]
 81→    pub fn with_model_cache_dir(mut self, dir: PathBuf) -> Self {
 82→        self.model_cache_dir = dir;
 83→        self
 84→    }
 85→
 86→    /// Create a context from the current working directory (no log directory).
 87→    pub fn from_cwd() -> anyhow::Result<Self> {
 88→        let cwd = std::env::current_dir()?;
 89→        Self::new(cwd)
 90→    }
 91→
 92→    /// Root directory of the project where mementor is enabled.
 93→    pub fn project_root(&self) -> &Path {
 94→        &self.project_root
 95→    }
 96→
 97→    /// The actual working directory at startup.
 98→    ///
 99→    /// May be a linked worktree or subdirectory that differs from
100→    /// [`Self::project_root`].
101→    pub fn cwd(&self) -> &Path {
102→        &self.cwd
103→    }
104→
105→    /// Returns `true` if the working directory is inside a linked (non-primary)
106→    /// git worktree.
107→    ///
108→    /// Determined at startup by [`crate::git::resolve_worktree`] based on the
109→    /// `.git` entry type — not by path comparison, so symlinks do not affect
110→    /// the result.
111→    pub fn is_linked_worktree(&self) -> bool {
112→        self.is_linked_worktree
113→    }
114→
115→    /// Optional parent directory for log file output.
116→    /// When set, operational logs are written to JSONL files under this path.
117→    pub fn log_dir(&self) -> Option<&Path> {
118→        self.log_dir.as_deref()
119→    }
120→
121→    /// Path to the mementor `SQLite` database file (`mementor.db`).
122→    /// Default: `<project_root>/.mementor/mementor.db`
123→    pub fn db_path(&self) -> PathBuf {
124→        self.mementor_dir().join("mementor.db")
125→    }
126→
127→    /// Directory where embedding model files are stored.
128→    pub fn model_cache_dir(&self) -> &Path {
129→        &self.model_cache_dir
130→    }
131→
132→    /// Path to the `.mementor/` directory.
133→    /// Default: `<project_root>/.mementor/`
134→    pub fn mementor_dir(&self) -> PathBuf {
135→        self.project_root.join(".mementor")
136→    }
137→
138→    /// Path to the Claude settings file.
139→    /// Default: `<project_root>/.claude/settings.json`
140→    pub fn claude_settings_path(&self) -> PathBuf {
141→        self.project_root.join(".claude").join("settings.json")
142→    }
143→
144→    /// Path to the project's `.gitignore` file.
145→    /// Default: `<project_root>/.gitignore`
146→    pub fn gitignore_path(&self) -> PathBuf {
147→        self.project_root.join(".gitignore")
148→    }
149→}
