17→
18→/// Main CLI entry point. Parses args and dispatches to the appropriate command.
19→pub fn try_run<IN, OUT, ERR>(
20→    args: &[&str],
21→    runtime: &Runtime,
22→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
23→) -> anyhow::Result<()>
24→where
25→    IN: Read,
26→    OUT: Write,
27→    ERR: Write,
28→{
29→    let cli = Cli::try_parse_from(args)?;
30→
31→    match cli.command {
32→        Command::Enable => commands::enable::run_enable(runtime, io),
33→        Command::Ingest {
34→            transcript,
35→            session_id,
36→        } => commands::ingest::run_ingest_cmd(&transcript, &session_id, runtime, io),
37→        Command::Model { model_command } => match model_command {
38→            ModelCommand::Download { force } => {
39→                commands::model::run_model_download(force, runtime, io)
40→            }
41→        },
42→        Command::Hook { hook_command } => match hook_command {
43→            HookCommand::Stop => {
44→                let input = hooks::input::read_stop_input(io.stdin())?;
45→                hooks::stop::handle_stop(&input, runtime, io)
46→            }
47→            HookCommand::PreCompact => {
48→                let input = hooks::input::read_pre_compact_input(io.stdin())?;
49→                hooks::pre_compact::handle_pre_compact(&input, runtime, io)
50→            }
51→        },
52→    }
53→}
