 1→use std::env;
 2→use std::io::Write;
 3→use std::path::PathBuf;
 4→
 5→fn main() {
 6→    let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").unwrap());
 7→    let vendor_src = manifest_dir.join("../../vendor/sqlite-vector/src");
 8→    let vendor_libs = manifest_dir.join("../../vendor/sqlite-vector/libs");
 9→
10→    // sqlite3.h is vendored alongside sqlite-vector sources.
11→    // This avoids depending on DEP_SQLITE3_INCLUDE from libsqlite3-sys,
12→    // which is not reliably available when build scripts run in parallel.
13→    let sqlite_include = &vendor_src;
14→
15→    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").unwrap();
16→    let target_os = env::var("CARGO_CFG_TARGET_OS").unwrap();
17→
18→    assert!(
19→        target_os == "macos",
20→        "Milestone 1 only supports macOS. Target OS: {target_os}"
21→    );
22→
23→    // Common files: sqlite-vector.c + distance-cpu.c
24→    let mut common = cc::Build::new();
25→    common
26→        .file(vendor_src.join("sqlite-vector.c"))
27→        .file(vendor_src.join("distance-cpu.c"))
28→        .include(&vendor_src)
29→        .include(&vendor_libs)
30→        .include(sqlite_include)
31→        .define("SQLITE_CORE", None)
32→        .warnings(false)
33→        .opt_level(2);
34→
35→    match target_arch.as_str() {
36→        "aarch64" => {
37→            // Apple Silicon: NEON is baseline, no extra flags needed.
38→            common.file(vendor_src.join("distance-neon.c"));
39→            common.compile("sqlite_vector");
40→        }
41→        "x86_64" => {
42→            // Intel Mac: SSE2 is baseline on all x86_64 CPUs.
43→            // Provide stubs that fall back to SSE2 for the missing
44→            // AVX2/AVX512 init functions. At runtime, if the CPU supports
45→            // AVX2 (or AVX512), distance-cpu.c calls init_distance_functions_avx2
46→            // (or avx512) which would skip SSE2 init entirely. Our stubs
47→            // redirect to SSE2 so the search still works correctly.
48→            let out_dir = PathBuf::from(env::var("OUT_DIR").unwrap());
49→            let stub_path = out_dir.join("distance_stubs.c");
50→            let mut stub = std::fs::File::create(&stub_path).unwrap();
51→            writeln!(stub, "extern void init_distance_functions_sse2(void);").unwrap();
52→            writeln!(
53→                stub,
54→                "void init_distance_functions_avx2(void) {{ init_distance_functions_sse2(); }}"
55→            )
56→            .unwrap();
57→            writeln!(
58→                stub,
59→                "void init_distance_functions_avx512(void) {{ init_distance_functions_sse2(); }}"
60→            )
61→            .unwrap();
62→
63→            common.file(vendor_src.join("distance-sse2.c"));
64→            common.file(&stub_path);
65→            common.compile("sqlite_vector");
66→        }
67→        _ => {
68→            panic!("Unsupported architecture: {target_arch}");
69→        }
70→    }
71→
72→    println!("cargo::rerun-if-changed=../../vendor/sqlite-vector/src");
