  1→//! Generates `crates/mementor-lib/ddl/schema.sql` from migration files.
  2→//!
  3→//! Run via: `cargo run -p mementor-schema-gen` or `mise run schema:dump`
  4→
  5→use std::path::PathBuf;
  6→
  7→use rusqlite::Connection;
  8→
  9→macro_rules! migration_ddl {
 10→    ($file:literal) => {
 11→        include_str!(concat!("../../mementor-lib/ddl/migrations/", $file))
 12→    };
 13→}
 14→
 15→/// All migration files in order. Add new entries here when creating migrations.
 16→const MIGRATIONS: &[&str] = &[
 17→    migration_ddl!("00001__initial_schema.sql"),
 18→    migration_ddl!("00002__schema_redesign.sql"),
 19→];
 20→
 21→fn main() {
 22→    let conn = Connection::open_in_memory().expect("Failed to open in-memory database");
 23→
 24→    // Apply all migrations sequentially
 25→    for (i, ddl) in MIGRATIONS.iter().enumerate() {
 26→        conn.execute_batch(ddl)
 27→            .unwrap_or_else(|e| panic!("Failed to apply migration {}: {e}", i + 1));
 28→    }
 29→
 30→    // Dump schema from sqlite_master
 31→    let schema = dump_schema(&conn);
 32→
 33→    // Write to schema.sql
 34→    let output_path = output_path();
 35→    std::fs::write(&output_path, &schema)
 36→        .unwrap_or_else(|e| panic!("Failed to write {}: {e}", output_path.display()));
 37→
 38→    println!("Schema written to {}", output_path.display());
 39→}
 40→
 41→/// Dump all CREATE statements from `sqlite_master`, excluding `SQLite` internals
 42→/// and FTS5 shadow tables (which are auto-created by the virtual table).
 43→fn dump_schema(conn: &Connection) -> String {
 44→    let mut stmt = conn
 45→        .prepare(
 46→            "SELECT sql FROM sqlite_master \
 47→             WHERE sql IS NOT NULL \
 48→             AND name NOT LIKE 'sqlite_%' \
 49→             AND NOT ( \
 50→                 sqlite_master.type = 'table' \
 51→                 AND EXISTS ( \
 52→                     SELECT 1 FROM sqlite_master vt \
 53→                     WHERE vt.sql LIKE 'CREATE VIRTUAL TABLE%' \
 54→                     AND sqlite_master.name LIKE vt.name || '_%' \
 55→                 ) \
 56→             ) \
 57→             ORDER BY \
 58→                 CASE type \
 59→                     WHEN 'table' THEN 0 \
 60→                     WHEN 'index' THEN 1 \
 61→                     ELSE 2 \
 62→                 END, \
 63→                 name",
 64→        )
 65→        .expect("Failed to prepare sqlite_master query");
 66→
 67→    let rows: Vec<String> = stmt
 68→        .query_map([], |row| row.get::<_, String>(0))
 69→        .expect("Failed to query sqlite_master")
 70→        .map(|r| r.expect("Failed to read row"))
 71→        .collect();
 72→
 73→    let mut output = String::new();
 74→    for (i, sql) in rows.iter().enumerate() {
 75→        output.push_str(sql);
 76→        output.push_str(";\n");
 77→        if i < rows.len() - 1 {
 78→            output.push('\n');
 79→        }
 80→    }
 81→
 82→    output
 83→}
 84→
 85→/// Resolve the output path relative to the crate's manifest directory.
 86→fn output_path() -> PathBuf {
 87→    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
 88→    manifest_dir.join("../mementor-lib/ddl/schema.sql")
 89→}
 90→
 91→#[cfg(test)]
 92→mod tests {
 93→    use super::*;
 94→
 95→    /// Verify that the bundled `schema.sql` snapshot matches what migrations produce.
 96→    ///
 97→    /// If this test fails, run `mise run schema:dump` to regenerate `schema.sql`.
 98→    #[test]
 99→    fn migrations_match_snapshot() {
100→        // Build schema from migrations
101→        let conn = Connection::open_in_memory().unwrap();
102→        for (i, ddl) in MIGRATIONS.iter().enumerate() {
103→            conn.execute_batch(ddl)
104→                .unwrap_or_else(|e| panic!("Failed to apply migration {}: {e}", i + 1));
105→        }
106→        let from_migrations = dump_schema(&conn);
107→
108→        // Build schema from snapshot
109→        let snapshot_conn = Connection::open_in_memory().unwrap();
110→        snapshot_conn
111→            .execute_batch(include_str!("../../mementor-lib/ddl/schema.sql"))
112→            .expect("Failed to apply schema.sql");
113→        let from_snapshot = dump_schema(&snapshot_conn);
114→
115→        assert_eq!(
116→            from_migrations, from_snapshot,
117→            "schema.sql is out of date. Run `mise run schema:dump` to regenerate."
118→        );
119→    }
120→}
