 5→use super::connection::{open_db, open_db_in_memory};
 6→
 7→/// Connection factory for `SQLite` databases.
 8→///
 9→/// `File` opens a file-backed database at the given path.
10→/// `InMemory` uses a named shared-cache in-memory database; the anchor
11→/// connection keeps the database alive for the lifetime of the driver.
12→pub enum DatabaseDriver {
13→    /// File-backed `SQLite` database.
14→    File(PathBuf),
15→    /// Named in-memory `SQLite` database with shared cache.
16→    /// The `_anchor` connection keeps the database alive.
17→    InMemory { name: String, _anchor: Connection },
18→}
19→
20→impl DatabaseDriver {
21→    /// Create a driver for a file-backed database.
22→    #[must_use]
23→    pub fn file(path: PathBuf) -> Self {
24→        Self::File(path)
25→    }
26→
27→    /// Create a driver for a named in-memory database.
28→    ///
29→    /// Opens an anchor connection that keeps the shared-cache database alive.
30→    /// Subsequent calls to [`open`](Self::open) return new connections to the
31→    /// same in-memory database.
32→    pub fn in_memory(name: &str) -> anyhow::Result<Self> {
33→        let anchor = open_db_in_memory(name)?;
34→        Ok(Self::InMemory {
35→            name: name.to_string(),
36→            _anchor: anchor,
37→        })
38→    }
39→
40→    /// Open a new connection to the underlying database.
41→    pub fn open(&self) -> anyhow::Result<Connection> {
42→        match self {
43→            Self::File(path) => open_db(path),
44→            Self::InMemory { name, .. } => open_db_in_memory(name),
45→        }
46→    }
47→
48→    /// Check whether the database is ready to use.
49→    ///
50→    /// For file-backed databases, this checks if the database file exists.
51→    /// For in-memory databases, this always returns `true` (the anchor
52→    /// connection guarantees the database is alive).
53→    #[must_use]
54→    pub fn is_ready(&self) -> bool {
55→        match self {
56→            Self::File(path) => path.exists(),
57→            Self::InMemory { .. } => true,
58→        }
59→    }
60→}
61→
