  1→use std::path::{Path, PathBuf};
  2→
  3→/// The result of resolving a working directory's git worktree status.
  4→///
  5→/// Returned by [`resolve_worktree`]. Classifies the working directory as being
  6→/// inside a primary worktree, a linked worktree, or not inside any git
  7→/// repository at all.
  8→#[derive(Debug, Clone, PartialEq, Eq)]
  9→pub enum ResolvedWorktree {
 10→    /// The working directory is inside a primary (non-linked) worktree.
 11→    /// Contains the primary worktree root (where `.git` is a directory).
 12→    Primary(PathBuf),
 13→    /// The working directory is inside a linked worktree.
 14→    /// Contains the resolved primary worktree root.
 15→    Linked(PathBuf),
 16→    /// The working directory is not inside any git repository.
 17→    NotGitRepo,
 18→}
 19→
 20→impl ResolvedWorktree {
 21→    /// Returns the primary worktree root, regardless of whether this is a
 22→    /// primary or linked worktree. Returns `None` if not in a git repo.
 23→    pub fn primary_root(&self) -> Option<&Path> {
 24→        match self {
 25→            Self::Primary(root) | Self::Linked(root) => Some(root),
 26→            Self::NotGitRepo => None,
 27→        }
 28→    }
 29→
 30→    /// Returns `true` if this is a linked (non-primary) worktree.
 31→    pub fn is_linked(&self) -> bool {
 32→        matches!(self, Self::Linked(_))
 33→    }
 34→}
 35→
 36→/// Classify the git worktree that contains `cwd` and resolve its primary root.
 37→///
 38→/// Walks up from `cwd` toward the filesystem root, looking for a `.git` entry:
 39→///
 40→/// - **Directory** (`.git/`): this is the primary worktree root.
 41→///   Returns [`ResolvedWorktree::Primary`].
 42→/// - **File** (`.git`): could be a linked worktree or a submodule.
 43→///   - If `<gitdir>/commondir` exists, this is a **linked worktree**. Follow
 44→///     the `commondir` chain to resolve the common `.git` directory and return
 45→///     [`ResolvedWorktree::Linked`] with the primary worktree root.
 46→///   - If `commondir` is absent, this is a **submodule**. Skip it and keep
 47→///     walking up — the submodule is part of the larger project.
 48→///
 49→/// Returns [`ResolvedWorktree::NotGitRepo`] if no `.git` entry is found at any
 50→/// ancestor, or if an I/O or parse error occurs.
 51→pub fn resolve_worktree(cwd: &Path) -> ResolvedWorktree {
 52→    let mut current = cwd.to_path_buf();
 53→
 54→    loop {
 55→        let git_entry = current.join(".git");
 56→
 57→        if git_entry.is_dir() {
 58→            return ResolvedWorktree::Primary(current);
 59→        }
 60→
 61→        if git_entry.is_file()
 62→            && let Some(root) = try_resolve_linked_worktree(&current, &git_entry)
 63→        {
 64→            return ResolvedWorktree::Linked(root);
 65→        }
 66→        // If .git is a file without commondir (submodule), skip and keep
 67→        // walking up.
 68→
 69→        if !current.pop() {
 70→            return ResolvedWorktree::NotGitRepo;
 71→        }
 72→    }
 73→}
 74→
 75→/// Try to resolve a linked worktree's `.git` file to the primary root.
 76→///
 77→/// Returns `Some(primary_root)` if this is a linked worktree (i.e.,
 78→/// `commondir` exists inside the gitdir). Returns `None` if it's a submodule
 79→/// (no `commondir`) or on any I/O/parse error.
 80→fn try_resolve_linked_worktree(dir: &Path, git_file: &Path) -> Option<PathBuf> {
 81→    let content = std::fs::read_to_string(git_file).ok()?;
 82→    let gitdir_ref = content.strip_prefix("gitdir: ")?.trim();
 83→
 84→    let gitdir = if Path::new(gitdir_ref).is_absolute() {
 85→        PathBuf::from(gitdir_ref)
 86→    } else {
 87→        dir.join(gitdir_ref)
 88→    };
 89→
 90→    // Only linked worktrees have a commondir file. Submodules do not.
 91→    let commondir_file = gitdir.join("commondir");
 92→    if !commondir_file.is_file() {
 93→        return None;
 94→    }
 95→
 96→    let commondir_ref = std::fs::read_to_string(&commondir_file).ok()?;
 97→    let commondir_ref = commondir_ref.trim();
 98→
 99→    let common_git_dir = if Path::new(commondir_ref).is_absolute() {
100→        PathBuf::from(commondir_ref)
101→    } else {
102→        gitdir.join(commondir_ref)
103→    };
104→
105→    let common_git_dir = std::fs::canonicalize(&common_git_dir).ok()?;
106→    let primary_root = common_git_dir.parent()?;
107→
108→    Some(primary_root.to_path_buf())
109→}
